UseScript:
foreach (var item in Object)
{
    foreach (var temp in item.dynamicVariables)
    {
        Self.dynamicVariables[temp.Key]=temp.Value;
    }

}
Self.dynamicVariables["liveCount"]=0f;

Self.Defend += int.Parse(def());
       int count=0;
               var buff = Self.GetBuff(DataId.buff_burn);
               if (buff != null)
               {
                   count += buff.buffConfig.Level;
               } 

       ChangeDefence((int.Parse(def())+count).ToString());

int k = int.Parse(PlayerInfo.GetGameVar("Difficulty")) > 3 ? 3 : 2;
for (int i = 0; i < k; i++)
{
    AddCard(DataId.cursecard_3);
}
Vars["ThisCount"] = (int.Parse(Vars["ThisCount"]) + 1).ToString();

foreach (var item in Object)
        {
                var buffs = item.GetBuff(DataId.SpecialBuff_GiantDollBear);
                if (buffs!=null)
                {
                    buffs.scriptExecutor.Vars["ThisCount"] = "1";
                }
        }

InitScript:
Vars["CD"]="2";AddDescription("1", "Damage", atk());
        if (int.Parse(PlayerInfo.GetTagDiff())>30)
        {
            Vars["priority"]="4";
        }
        else
        {
            Vars["priority"]="0";
        }

UseScript:
SetStatus("Target");
        for (int i = 0; i < 5; i++)
        {
           Damage((int.Parse(atk())/5).ToString()); 
        }
